/* Data access layer.
 *
 * Live (CORS-enabled, fetched straight from the browser):
 *   - USGS NWIS instantaneous/daily/statistics services
 *   - NWS api.weather.gov forecasts
 * Static (generated by scripts/fetch_data.py via GitHub Actions, because
 * CDEC sends no CORS headers):
 *   - data/flow.json, snow.json, soil.json, reservoirs.json, meta.json
 */

const USGS = "https://waterservices.usgs.gov/nwis";

async function fetchJSON(url, opts) {
  const r = await fetch(url, opts);
  if (!r.ok) throw new Error(`${r.status} ${url}`);
  return r.json();
}

async function fetchText(url) {
  const r = await fetch(url);
  if (!r.ok) throw new Error(`${r.status} ${url}`);
  return r.text();
}

/* ---------- local (CDEC-derived) ---------- */

export async function loadLocal(name) {
  try {
    return await fetchJSON(`data/${name}.json?v=${Date.now() >> 16}`);
  } catch (e) {
    console.warn(`local data missing: ${name}`, e);
    return null;
  }
}

/* ---------- USGS ---------- */

// Latest instantaneous values for many sites in one call.
export async function usgsLatest(sites, param = "00060") {
  if (!sites.length) return {};
  const out = {};
  // NWIS caps the sites list; chunk to be safe.
  for (let i = 0; i < sites.length; i += 20) {
    const chunk = sites.slice(i, i + 20);
    const url = `${USGS}/iv/?format=json&sites=${chunk.join(",")}&parameterCd=${param}&siteStatus=all`;
    try {
      const j = await fetchJSON(url);
      for (const ts of j.value.timeSeries) {
        const site = ts.sourceInfo.siteCode[0].value;
        const v = ts.values[0]?.value?.at(-1);
        if (v && v.value !== "-999999") {
          out[site] = { v: +v.value, t: v.dateTime };
        }
      }
    } catch (e) {
      console.warn("usgsLatest chunk failed", e);
    }
  }
  return out;
}

// Daily-mean discharge for the trailing year.
export async function usgsDaily(site, days = 365, param = "00060") {
  const url = `${USGS}/dv/?format=json&sites=${site}&parameterCd=${param}&statCd=00003&period=P${days}D`;
  const j = await fetchJSON(url);
  const ts = j.value.timeSeries[0];
  if (!ts) return { dates: [], values: [] };
  const dates = [], values = [];
  for (const p of ts.values[0].value) {
    if (p.value === "-999999") continue;
    dates.push(p.dateTime.slice(0, 10));
    values.push(+p.value);
  }
  return { dates, values };
}

// Day-of-year percentile bands from the NWIS daily-statistics service.
// Returns arrays of length 366 indexed by (doy - 1), matching the CDEC JSON shape.
export async function usgsBands(site, param = "00060") {
  const url = `${USGS}/stat/?format=rdb&sites=${site}&statReportType=daily&statTypeCd=all&parameterCd=${param}`;
  const text = await fetchText(url);
  const lines = text.split("\n").filter((l) => l && !l.startsWith("#"));
  if (lines.length < 3) return null;
  const cols = lines[0].split("\t");
  const idx = Object.fromEntries(cols.map((c, i) => [c, i]));
  const need = ["month_nu", "day_nu", "min_va", "max_va", "p10_va", "p25_va", "p50_va", "p75_va", "p90_va"];
  if (!need.every((c) => c in idx)) return null;
  const mk = () => new Array(366).fill(null);
  const bands = { min: mk(), p10: mk(), p25: mk(), p50: mk(), p75: mk(), p90: mk(), max: mk() };
  let seenTs = null;
  for (const line of lines.slice(2)) {
    const f = line.split("\t");
    if (f.length < cols.length) continue;
    // A site can carry several time series (ts_id); keep only the first.
    const ts = f[idx.ts_id];
    if (seenTs === null) seenTs = ts;
    if (ts !== seenTs) continue;
    const doy = dayOfYear(+f[idx.month_nu], +f[idx.day_nu]);
    if (!doy) continue;
    const put = (key, col) => {
      const v = parseFloat(f[idx[col]]);
      if (!Number.isNaN(v)) bands[key][doy - 1] = v;
    };
    put("min", "min_va"); put("max", "max_va");
    put("p10", "p10_va"); put("p25", "p25_va"); put("p50", "p50_va");
    put("p75", "p75_va"); put("p90", "p90_va");
  }
  for (const k of Object.keys(bands)) smoothInPlace(bands[k], 11);
  return bands;
}

// doy on a leap-year calendar (so Feb 29 = 60), consistent with pandas dayofyear
export function dayOfYear(month, day) {
  const cum = [0, 31, 60, 91, 121, 152, 182, 213, 244, 274, 305, 335];
  if (month < 1 || month > 12) return null;
  return cum[month - 1] + day;
}

function smoothInPlace(arr, window) {
  const n = arr.length, half = window >> 1, src = arr.slice();
  for (let i = 0; i < n; i++) {
    let s = 0, c = 0;
    for (let k = -half; k <= half; k++) {
      const v = src[(i + k + n) % n];
      if (v !== null && !Number.isNaN(v)) { s += v; c++; }
    }
    arr[i] = c ? s / c : null;
  }
}

/* ---------- CNRFC river forecast (NOAA NWPS API, CORS ok) ---------- */

export async function nwpsForecast(gaugeId) {
  const j = await fetchJSON(`https://api.water.noaa.gov/nwps/v1/gauges/${gaugeId}/stageflow/forecast`);
  const scale = j.secondaryUnits === "kcfs" ? 1000 : 1;
  const now = Date.now();
  const t = [], v = [];
  for (const p of j.data || []) {
    if (p.secondary == null || p.secondary < 0) continue;
    // forecast series can begin a few hours in the past; keep future points only
    if (new Date(p.validTime).getTime() <= now) continue;
    t.push(p.validTime);
    v.push(p.secondary * scale);
  }
  return t.length ? { t, v } : null;
}

/* ---------- NWS ---------- */

const NWS_HEADERS = { headers: { Accept: "application/geo+json" } };

export async function nwsForecast(lat, lon) {
  const pt = await fetchJSON(`https://api.weather.gov/points/${lat.toFixed(4)},${lon.toFixed(4)}`, NWS_HEADERS);
  const [fc, grid] = await Promise.all([
    fetchJSON(pt.properties.forecast, NWS_HEADERS),
    fetchJSON(pt.properties.forecastGridData, NWS_HEADERS),
  ]);
  return {
    periods: fc.properties.periods,
    qpf: parseGridQPF(grid.properties.quantitativePrecipitation),
    snow: parseGridQPF(grid.properties.snowfallAmount),
  };
}

// NWS grid values are {validTime: "2026-07-01T18:00:00+00:00/PT6H", value: mm}.
// Spread each interval's total across days -> {dayISO: inches}.
function parseGridQPF(prop) {
  const byDay = {};
  if (!prop || !prop.values) return byDay;
  for (const { validTime, value } of prop.values) {
    if (value == null) continue;
    const [startStr, durStr] = validTime.split("/");
    const start = new Date(startStr);
    const hours = isoDurationHours(durStr) || 1;
    const inches = value / 25.4;
    const perHour = inches / hours;
    for (let h = 0; h < hours; h++) {
      const d = new Date(start.getTime() + h * 3600e3);
      const key = localDayISO(d);
      byDay[key] = (byDay[key] || 0) + perHour;
    }
  }
  return byDay;
}

function isoDurationHours(dur) {
  const m = dur.match(/P(?:(\d+)D)?(?:T(?:(\d+)H)?)?/);
  if (!m) return 1;
  return (+(m[1] || 0)) * 24 + (+(m[2] || 0));
}

function localDayISO(d) {
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
}
